#ifndef UI_COMPONENT_H
#define UI_COMPONENT_H

#include <stdint.h>

namespace NanoUI {

/**
 * @brief Maximum length for component ID strings
 */
#define MAX_ID_LEN 16

/**
 * @brief Maximum length for label/text strings
 */
#define MAX_TEXT_LEN 32

/**
 * @brief Event structure passed to callbacks
 */
struct UIEvent {
    char id[MAX_ID_LEN];
    int value;
    bool toggled;
};

/**
 * @brief Base class for all UI components
 * 
 * All visual elements (buttons, labels, sliders, etc.) inherit from this class.
 * Provides common properties like position, size, visibility, and enabled state.
 */
class UIComponent {
public:
    char id[MAX_ID_LEN];
    int16_t x;
    int16_t y;
    int16_t width;
    int16_t height;
    bool visible;
    bool enabled;
    bool needsRedraw;

    UIComponent() : x(0), y(0), width(0), height(0), visible(true), enabled(true), needsRedraw(true) {
        id[0] = '\0';
    }

    virtual ~UIComponent() {}

    /**
     * @brief Get the type of this component as a string
     * @return Component type name (e.g., "button", "label")
     */
    virtual const char* getType() const = 0;

    /**
     * @brief Render this component to the display
     * @param driver Pointer to the display driver interface
     */
    virtual void draw(class IDriver* driver) = 0;

    /**
     * @brief Handle touch events within this component's bounds
     * @param touchX X coordinate of touch
     * @param touchY Y coordinate of touch
     * @param pressed True if touch is currently pressed
     * @return True if the touch was handled by this component
     */
    virtual bool handleTouch(int16_t touchX, int16_t touchY, bool pressed) = 0;

    /**
     * @brief Check if a point is inside this component's bounding box
     * @param px X coordinate
     * @param py Y coordinate
     * @return True if the point is inside
     */
    bool contains(int16_t px, int16_t py) const {
        return visible && px >= x && px < x + width && py >= y && py < y + height;
    }

    /**
     * @brief Set the text/label of this component
     * @param text New text string
     */
    virtual void setText(const char* text) {}

    /**
     * @brief Set the numeric value of this component
     * @param value New value
     */
    virtual void setValue(int value) {}

    /**
     * @brief Get the current numeric value of this component
     * @return Current value
     */
    virtual int getValue() const { return 0; }
};

} // namespace NanoUI

#endif // UI_COMPONENT_H

#ifndef IDRIVER_H
#define IDRIVER_H

#include <stdint.h>

namespace NanoUI {

/**
 * @brief Abstract display driver interface
 * 
 * Defines the contract that all display drivers must implement.
 * This allows NanoUI to work with different display controllers
 * (ILI9341, ST7789, etc.) without code changes.
 */
class IDriver {
public:
    virtual ~IDriver() {}

    /**
     * @brief Initialize the display hardware
     */
    virtual void init() = 0;

    /**
     * @brief Fill the entire screen with a color
     * @param color RGB565 color value
     */
    virtual void fillScreen(uint16_t color) = 0;

    /**
     * @brief Draw a filled rectangle
     * @param x Top-left X coordinate
     * @param y Top-left Y coordinate
     * @param w Width in pixels
     * @param h Height in pixels
     * @param color RGB565 color value
     */
    virtual void fillRect(int16_t x, int16_t y, int16_t w, int16_t h, uint16_t color) = 0;

    /**
     * @brief Draw a rectangle outline
     * @param x Top-left X coordinate
     * @param y Top-left Y coordinate
     * @param w Width in pixels
     * @param h Height in pixels
     * @param color RGB565 color value
     */
    virtual void drawRect(int16_t x, int16_t y, int16_t w, int16_t h, uint16_t color) = 0;

    /**
     * @brief Draw a filled circle
     * @param x Center X coordinate
     * @param y Center Y coordinate
     * @param r Radius in pixels
     * @param color RGB565 color value
     */
    virtual void fillCircle(int16_t x, int16_t y, int16_t r, uint16_t color) = 0;

    /**
     * @brief Draw a line
     * @param x0 Start X coordinate
     * @param y0 Start Y coordinate
     * @param x1 End X coordinate
     * @param y1 End Y coordinate
     * @param color RGB565 color value
     */
    virtual void drawLine(int16_t x0, int16_t y0, int16_t x1, int16_t y1, uint16_t color) = 0;

    /**
     * @brief Draw a single pixel
     * @param x X coordinate
     * @param y Y coordinate
     * @param color RGB565 color value
     */
    virtual void drawPixel(int16_t x, int16_t y, uint16_t color) = 0;

    /**
     * @brief Draw a bitmap image
     * @param x Top-left X coordinate
     * @param y Top-left Y coordinate
     * @param w Width in pixels
     * @param h Height in pixels
     * @param data Pointer to RGB565 image data in PROGMEM
     */
    virtual void drawRGBBitmap(int16_t x, int16_t y, int16_t w, int16_t h, const uint16_t* data) = 0;

    /**
     * @brief Set the text cursor position
     * @param x X coordinate
     * @param y Y coordinate
     */
    virtual void setCursor(int16_t x, int16_t y) = 0;

    /**
     * @brief Set the text color
     * @param color RGB565 color value
     */
    virtual void setTextColor(uint16_t color) = 0;

    /**
     * @brief Set the text size multiplier
     * @param size Size multiplier (1 = default)
     */
    virtual void setTextSize(uint8_t size) = 0;

    /**
     * @brief Print a string at the current cursor position
     * @param str Null-terminated string
     */
    virtual void print(const char* str) = 0;

    /**
     * @brief Print an integer at the current cursor position
     * @param n Integer value
     */
    virtual void print(int n) = 0;

    /**
     * @brief Get display width in pixels
     * @return Width
     */
    virtual int16_t width() const = 0;

    /**
     * @brief Get display height in pixels
     * @return Height
     */
    virtual int16_t height() const = 0;

    /**
     * @brief Set display rotation
     * @param rotation Rotation value (0-3)
     */
    virtual void setRotation(uint8_t rotation) = 0;
};

} // namespace NanoUI

#endif // IDRIVER_H

#ifndef ILI9341_DRIVER_H
#define ILI9341_DRIVER_H

#include "IDriver.h"
