#ifndef UI_PARSER_H
#define UI_PARSER_H

#include <ArduinoJson.h>
#include "../components/UIComponent.h"

namespace NanoUI {

/**
 * @brief Maximum number of components per screen
 */
#ifndef MAX_COMPONENTS_PER_SCREEN
#define MAX_COMPONENTS_PER_SCREEN 20
#endif

/**
 * @brief Maximum number of screens
 */
#ifndef MAX_SCREENS
#define MAX_SCREENS 5
#endif

/**
 * @brief Forward declaration
 */
class UIScreen;

/**
 * @brief JSON UI definition parser
 * 
 * Parses .ui.json files/streams and constructs UIScreen and UIComponent objects.
 * Uses ArduinoJson streaming parser to minimize memory usage on Arduino Uno/Nano.
 */
class UIParser {
public:
    UIParser();

    /**
     * @brief Parse a JSON string from PROGMEM/flash memory
     * @param jsonStr Null-terminated JSON string
     * @param screens Output array to store parsed screens
     * @param maxScreens Maximum number of screens the array can hold
     * @return Number of screens successfully parsed
     */
    int parseFromFlash(const char* jsonStr, UIScreen* screens, int maxScreens);

    /**
     * @brief Parse a JSON file from SD card (if available)
     * @param path File path on SD card
     * @param screens Output array to store parsed screens
     * @param maxScreens Maximum number of screens the array can hold
     * @return Number of screens successfully parsed, or -1 on file error
     */
    int parseFromSD(const char* path, UIScreen* screens, int maxScreens);

    /**
     * @brief Convert a hex color string to RGB565
     * @param hexStr Color in "#RRGGBB" format
     * @return RGB565 color value, default black on error
     */
    static uint16_t parseColor(const char* hexStr);

    /**
     * @brief Get the last error message
     * @return Error description string
     */
    const char* getLastError() const { return _lastError; }

private:
    char _lastError[48];

    bool parseScreen(JsonObjectConst screenObj, UIScreen& screen);
    UIComponent* parseComponent(JsonObjectConst compObj);
    void parseStyle(JsonObjectConst styleObj, UIComponent* comp);
};

} // namespace NanoUI

#endif // UI_PARSER_H

#include "UIParser.h"
#include "UIScreen.h"
#include "../components/UIButton.h"
#include "../components/UILabel.h"
#include "../components/UIToggle.h"
#include "../components/UISlider.h"
#include "../components/UIImage.h"
#include <string.h>

namespace NanoUI {

UIParser::UIParser() {
    _lastError[0] = '\0';
}

uint16_t UIParser::parseColor(const char* hexStr) {
    if (!hexStr || hexStr[0] != '#') return 0x0000;

    long rgb = strtol(hexStr + 1, NULL, 16);
    uint8_t r = (rgb >> 16) & 0xFF;
    uint8_t g = (rgb >> 8) & 0xFF;
    uint8_t b = rgb & 0xFF;

    return ((r & 0xF8) << 8) | ((g & 0xFC) << 3) | (b >> 3);
}

int UIParser::parseFromFlash(const char* jsonStr, UIScreen* screens, int maxScreens) {
    if (!jsonStr || !screens || maxScreens <= 0) {
        strncpy(_lastError, "Invalid arguments", sizeof(_lastError));
        return 0;
    }

    JsonDocument doc;
    DeserializationError error = deserializeJson(doc, jsonStr);

    if (error) {
        strncpy(_lastError, error.c_str(), sizeof(_lastError));
        return 0;
    }

    JsonArray screensArr = doc["screens"];
    if (!screensArr) {
        strncpy(_lastError, "Missing screens array", sizeof(_lastError));
        return 0;
    }

    int count = 0;
    for (JsonObject screenObj : screensArr) {
        if (count >= maxScreens) break;
        if (parseScreen(screenObj, screens[count])) {
            count++;
        }
    }

    return count;
}

int UIParser::parseFromSD(const char* path, UIScreen* screens, int maxScreens) {
    // SD card support can be added here by opening the file and streaming to ArduinoJson
    // For now, return error to indicate not implemented in base
    strncpy(_lastError, "SD not implemented", sizeof(_lastError));
    (void)path;
    (void)screens;
    (void)maxScreens;
    return -1;
}

bool UIParser::parseScreen(JsonObject screenObj, UIScreen& screen) {
    const char* id = screenObj["id"];
    if (!id) {
        strncpy(_lastError, "Screen missing id", sizeof(_lastError));
        return false;
    }
    screen.setId(id);

    const char* bg = screenObj["background"];
    screen.backgroundColor = bg ? parseColor(bg) : 0x0000;

    JsonArray componentsArr = screenObj["components"];
    if (!componentsArr) return true;

    for (JsonObject compObj : componentsArr) {
        if (screen.componentCount >= MAX_COMPONENTS_PER_SCREEN) break;
        UIComponent* comp = parseComponent(compObj);
        if (comp) {
            screen.addComponent(comp);
        }
    }

    return true;
}

UIComponent* UIParser::parseComponent(JsonObject compObj) {
    const char* type = compObj["type"];
    if (!type) return nullptr;

    UIComponent* comp = nullptr;

    if (strcmp(type, "button") == 0) {
        comp = new UIButton();
    } else if (strcmp(type, "label") == 0) {
        comp = new UILabel();
    } else if (strcmp(type, "toggle") == 0) {
        comp = new UIToggle();
    } else if (strcmp(type, "slider") == 0) {
        comp = new UISlider();
    } else if (strcmp(type, "image") == 0) {
        comp = new UIImage();
    } else {
        return nullptr;
    }

    // Parse common properties
    const char* id = compObj["id"];
    if (id) strncpy(comp->id, id, MAX_ID_LEN - 1);
    comp->id[MAX_ID_LEN - 1] = '\0';

    comp->x = compObj["x"] | 0;
    comp->y = compObj["y"] | 0;
    comp->width = compObj["width"] | 0;
    comp->height = compObj["height"] | 0;

    // Parse type-specific properties
    if (strcmp(type, "button") == 0) {
        UIButton* btn = static_cast<UIButton*>(comp);
        const char* label = compObj["label"];
        if (label) btn->setText(label);
        const char* action = compObj["onPress"];
        if (action) btn->setAction(action);
        JsonObject onPressObj = compObj["onPress"];
        if (onPressObj) {
            const char* act = onPressObj["action"];
            if (act && strcmp(act, "navigate") == 0) {
                btn->actionType = UIButton::ActionType::Navigate;
                const char* target = onPressObj["target"];
                if (target) btn->setTarget(target);
            }
        }
    } else if (strcmp(type, "label") == 0) {
        UILabel* lbl = static_cast<UILabel*>(comp);
        const char* text = compObj["text"];
        if (text) lbl->setText(text);
    } else if (strcmp(type, "toggle") == 0) {
        UIToggle* tgl = static_cast<UIToggle*>(comp);
        tgl->toggled = compObj["default"] | false;
        const char* action = compObj["onChange"];
        if (action) tgl->setAction(action);
    } else if (strcmp(type, "slider") == 0) {
        UISlider* sld = static_cast<UISlider*>(comp);
        sld->minValue = compObj["min"] | 0;
        sld->maxValue = compObj["max"] | 100;
        sld->setValue(compObj["value"] | sld->minValue);
        const char* action = compObj["onChange"];
        if (action) sld->setAction(action);
    } else if (strcmp(type, "image") == 0) {
        UIImage* img = static_cast<UIImage*>(comp);
        const char* src = compObj["src"];
        if (src) img->setSource(src);
    }

    // Parse style
    parseStyle(compObj["style"], comp);

    return comp;
}

void UIParser::parseStyle(JsonObject styleObj, UIComponent* comp) {
    if (!styleObj || !comp) return;

    const char* type = comp->getType();

    if (strcmp(type, "button") == 0) {
        UIButton* btn = static_cast<UIButton*>(comp);
        const char* bg = styleObj["bg"];
        if (bg) btn->bgColor = parseColor(bg);
        const char* text = styleObj["text"];
        if (text) btn->textColor = parseColor(text);
        btn->radius = styleObj["radius"] | 4;
        btn->fontSize = styleObj["fontSize"] | 2;
    } else if (strcmp(type, "label") == 0) {
        UILabel* lbl = static_cast<UILabel*>(comp);
        const char* color = styleObj["color"];
        if (color) lbl->textColor = parseColor(color);
        lbl->fontSize = styleObj["fontSize"] | 2;
        const char* align = styleObj["align"];
        if (align) lbl->align = align[0];
    } else if (strcmp(type, "toggle") == 0) {
        UIToggle* tgl = static_cast<UIToggle*>(comp);
        const char* active = styleObj["activeColor"];
        if (active) tgl->activeColor = parseColor(active);
        const char* inactive = styleObj["inactiveColor"];
        if (inactive) tgl->inactiveColor = parseColor(inactive);
    } else if (strcmp(type, "slider") == 0) {
        UISlider* sld = static_cast<UISlider*>(comp);
        const char* track = styleObj["trackColor"];
        if (track) sld->trackColor = parseColor(track);
        const char* thumb = styleObj["thumbColor"];
        if (thumb) sld->thumbColor = parseColor(thumb);
    }
}

} // namespace NanoUI

#ifndef UI_SCREEN_H
#define UI_SCREEN_H

#include "../components/UIComponent.h"

namespace NanoUI {

/**
 * @brief Maximum length for screen ID strings
 */
#define MAX_SCREEN_ID_LEN 16

/**
 * @brief Represents a single screen/page in the UI
 * 
 * A screen contains a background color and a collection of UI components.
 * Only one screen is visible at a time.
 */
class UIScreen {
public:
    char id[MAX_SCREEN_ID_LEN];
    uint16_t backgroundColor;
    UIComponent* components[MAX_COMPONENTS_PER_SCREEN];
    uint8_t componentCount;

    UIScreen() : backgroundColor(0x0000), componentCount(0) {
        id[0] = '\0';
        for (int i = 0; i < MAX_COMPONENTS_PER_SCREEN; i++) {
            components[i] = nullptr;
        }
    }

    ~UIScreen() {
        for (int i = 0; i < componentCount; i++) {
            if (components[i]) {
                delete components[i];
                components[i] = nullptr;
            }
        }
    }

    /**
     * @brief Set the screen ID
     * @param screenId ID string
     */
    void setId(const char* screenId) {
        if (screenId) {
            strncpy(id, screenId, MAX_SCREEN_ID_LEN - 1);
            id[MAX_SCREEN_ID_LEN - 1] = '\0';
        }
    }

    /**
     * @brief Add a component to this screen
     * @param comp Pointer to the component (ownership transferred)
     */
    void addComponent(UIComponent* comp) {
        if (componentCount < MAX_COMPONENTS_PER_SCREEN && comp) {
            components[componentCount++] = comp;
        }
    }

    /**
     * @brief Find a component by its ID
     * @param compId Component ID string
     * @return Pointer to the component, or nullptr if not found
     */
    UIComponent* findComponent(const char* compId) const {
        for (uint8_t i = 0; i < componentCount; i++) {
            if (components[i] && strcmp(components[i]->id, compId) == 0) {
                return components[i];
            }
        }
        return nullptr;
    }
};

} // namespace NanoUI

#endif // UI_SCREEN_H

#include "UIScreen.h"

namespace NanoUI {

// Implementation is header-only for simplicity on Arduino

} // namespace NanoUI

#ifndef UI_RENDERER_H
#define UI_RENDERER_H

#include "../drivers/IDriver.h"
#include "UIScreen.h"

namespace NanoUI {

/**
 * @brief Screen and component renderer
 * 
 * Handles drawing screens and their components to the display.
 * Manages dirty-region tracking for efficient redraws.
 */
class UIRenderer {
private:
    IDriver* _driver;

public:
    explicit UIRenderer(IDriver* driver) : _driver(driver) {}

    /**
     * @brief Render an entire screen
     * @param screen Pointer to the screen to render
     */
    void renderScreen(UIScreen* screen);

    /**
     * @brief Render a single component
     * @param comp Pointer to the component
     */
    void renderComponent(UIComponent* comp);

    /**
     * @brief Set the display driver
     * @param driver Pointer to the driver
     */
    void setDriver(IDriver* driver) { _driver = driver; }

    /**
     * @brief Get the current display driver
     * @return Pointer to the driver
     */
    IDriver* getDriver() const { return _driver; }
};

} // namespace NanoUI

#endif // UI_RENDERER_H

#include "UIRenderer.h"

namespace NanoUI {

void UIRenderer::renderScreen(UIScreen* screen) {
    if (!_driver || !screen) return;

    _driver->fillScreen(screen->backgroundColor);

    for (uint8_t i = 0; i < screen->componentCount; i++) {
        UIComponent* comp = screen->components[i];
        if (comp && comp->visible) {
            comp->needsRedraw = true;
            comp->draw(_driver);
            comp->needsRedraw = false;
        }
    }
}

void UIRenderer::renderComponent(UIComponent* comp) {
    if (!_driver || !comp || !comp->visible) return;
    comp->needsRedraw = true;
    comp->draw(_driver);
    comp->needsRedraw = false;
}

} // namespace NanoUI

#ifndef TOUCH_HANDLER_H
#define TOUCH_HANDLER_H

#include <stdint.h>

namespace NanoUI {

/**
 * @brief Touch calibration data
 */
struct TouchCalibration {
    int16_t xMin;
    int16_t xMax;
    int16_t yMin;
    int16_t yMax;
    bool swapXY;
};

/**
 * @brief Abstract touch handler interface
 * 
 * Handles touch input processing including calibration and coordinate mapping.
 * Implementations should wrap specific touch libraries (XPT2046, resistive, etc.).
 */
class TouchHandler {
private:
    TouchCalibration _cal;
    int16_t _displayWidth;
    int16_t _displayHeight;
    bool _wasPressed;
    int16_t _lastX;
    int16_t _lastY;

public:
    TouchHandler();

    /**
     * @brief Set display dimensions for coordinate mapping
     * @param w Display width
     * @param h Display height
     */
    void setDisplaySize(int16_t w, int16_t h);

    /**
     * @brief Set calibration parameters
     * @param cal Calibration data
     */
    void setCalibration(const TouchCalibration& cal);

    /**
     * @brief Update touch state - call this in loop()
     * @return True if touch state changed
     */
    bool update();

    /**
     * @brief Check if screen is currently touched
     * @return True if pressed
     */
    bool isPressed() const;

    /**
     * @brief Get current mapped X coordinate
     * @return X coordinate in display space
     */
    int16_t getX() const { return _lastX; }

    /**
     * @brief Get current mapped Y coordinate
     * @return Y coordinate in display space
     */
    int16_t getY() const { return _lastY; }

    /**
     * @brief Check if touch was just released (rising edge)
     * @return True if released this update
     */
    bool wasReleased() const;

    /**
     * @brief Raw touch reading - implement in subclass
     * @param x Output raw X
     * @param y Output raw Y
     * @param z Output pressure
     * @return True if touched
     */
    virtual bool readRaw(int16_t& x, int16_t& y, int16_t& z) = 0;

protected:
    /**
     * @brief Map raw touch coordinates to display coordinates
     * @param rawX Raw X
     * @param rawY Raw Y
     * @param outX Mapped X
     * @param outY Mapped Y
     */
    void mapCoordinates(int16_t rawX, int16_t rawY, int16_t& outX, int16_t& outY);
};

} // namespace NanoUI

#endif // TOUCH_HANDLER_H

#include "TouchHandler.h"
#include <Arduino.h>

namespace NanoUI {

TouchHandler::TouchHandler() 
    : _cal{300, 3800, 300, 3800, false}, 
      _displayWidth(320), _displayHeight(240),
      _wasPressed(false), _lastX(0), _lastY(0) {
}

void TouchHandler::setDisplaySize(int16_t w, int16_t h) {
    _displayWidth = w;
    _displayHeight = h;
}

void TouchHandler::setCalibration(const TouchCalibration& cal) {
    _cal = cal;
}

bool TouchHandler::update() {
    int16_t rawX, rawY, rawZ;
    bool pressed = readRaw(rawX, rawY, rawZ);

    if (pressed) {
        mapCoordinates(rawX, rawY, _lastX, _lastY);
    }

    bool changed = (pressed != _wasPressed);
    _wasPressed = pressed;
    return changed;
}

bool TouchHandler::isPressed() const {
    return _wasPressed;
}

bool TouchHandler::wasReleased() const {
    // This is checked externally by comparing previous state
    return false;
}

void TouchHandler::mapCoordinates(int16_t rawX, int16_t rawY, int16_t& outX, int16_t& outY) {
    long mappedX, mappedY;

    if (_cal.swapXY) {
        mappedX = map((long)rawY, _cal.yMin, _cal.yMax, 0, _displayWidth - 1);
        mappedY = map((long)rawX, _cal.xMin, _cal.xMax, 0, _displayHeight - 1);
    } else {
        mappedX = map((long)rawX, _cal.xMin, _cal.xMax, 0, _displayWidth - 1);
        mappedY = map((long)rawY, _cal.yMin, _cal.yMax, 0, _displayHeight - 1);
    }

    // Clamp values
    if (mappedX < 0) mappedX = 0;
    if (mappedX >= _displayWidth) mappedX = _displayWidth - 1;
    if (mappedY < 0) mappedY = 0;
    if (mappedY >= _displayHeight) mappedY = _displayHeight - 1;

    outX = (int16_t)mappedX;
    outY = (int16_t)mappedY;
}

} // namespace NanoUI

