#ifndef UI_BUTTON_H
#define UI_BUTTON_H

#include "UIComponent.h"
#include "../drivers/IDriver.h"
#include <string.h>

namespace NanoUI {

/**
 * @brief Interactive button component
 * 
 * Supports press actions, custom styling with rounded corners,
 * and navigation targets.
 */
class UIButton : public UIComponent {
public:
    enum class ActionType {
        Callback,
        Navigate
    };

    char label[MAX_TEXT_LEN];
    uint16_t bgColor;
    uint16_t textColor;
    uint8_t radius;
    uint8_t fontSize;
    ActionType actionType;
    char actionName[MAX_ID_LEN];
    char navigateTarget[MAX_ID_LEN];
    bool isPressed;

    UIButton() 
        : bgColor(0x07E0), textColor(0xFFFF), radius(4), fontSize(2),
          actionType(ActionType::Callback), isPressed(false) {
        label[0] = '\0';
        actionName[0] = '\0';
        navigateTarget[0] = '\0';
    }

    const char* getType() const override { return "button"; }

    void setText(const char* text) override {
        if (text) {
            strncpy(label, text, MAX_TEXT_LEN - 1);
            label[MAX_TEXT_LEN - 1] = '\0';
            needsRedraw = true;
        }
    }

    void setAction(const char* action) {
        if (action) {
            strncpy(actionName, action, MAX_ID_LEN - 1);
            actionName[MAX_ID_LEN - 1] = '\0';
            actionType = ActionType::Callback;
        }
    }

    void setTarget(const char* target) {
        if (target) {
            strncpy(navigateTarget, target, MAX_ID_LEN - 1);
            navigateTarget[MAX_ID_LEN - 1] = '\0';
            actionType = ActionType::Navigate;
        }
    }

    void draw(IDriver* driver) override;
    bool handleTouch(int16_t touchX, int16_t touchY, bool pressed) override;
};

} // namespace NanoUI

#endif // UI_BUTTON_H

#include "UIButton.h"
#include <string.h>

namespace NanoUI {

void UIButton::draw(IDriver* driver) {
    if (!driver || !visible) return;

    uint16_t drawBg = isPressed ? (uint16_t)(((bgColor >> 1) & 0x7BEF) | 0x0000) : bgColor;

    // Draw rounded rectangle background
    driver->fillRect(x + radius, y, width - 2 * radius, height, drawBg);
    driver->fillRect(x, y + radius, width, height - 2 * radius, drawBg);
    driver->fillCircle(x + radius, y + radius, radius, drawBg);
    driver->fillCircle(x + width - radius - 1, y + radius, radius, drawBg);
    driver->fillCircle(x + radius, y + height - radius - 1, radius, drawBg);
    driver->fillCircle(x + width - radius - 1, y + height - radius - 1, radius, drawBg);

    // Draw text centered
    driver->setTextColor(textColor);
    driver->setTextSize(fontSize);

    int16_t textW = strlen(label) * 6 * fontSize;
    int16_t textH = 8 * fontSize;
    int16_t textX = x + (width - textW) / 2;
    int16_t textY = y + (height - textH) / 2;

    driver->setCursor(textX, textY);
    driver->print(label);
}

bool UIButton::handleTouch(int16_t touchX, int16_t touchY, bool pressed) {
    if (!enabled || !visible) return false;

    bool inside = contains(touchX, touchY);
    if (inside && pressed) {
        if (!isPressed) {
            isPressed = true;
            needsRedraw = true;
        }
        return true;
    }

    if (isPressed && !pressed) {
        isPressed = false;
        needsRedraw = true;
        return inside;
    }

    if (isPressed && !inside) {
        isPressed = false;
        needsRedraw = true;
    }

    return false;
}

} // namespace NanoUI

