#include <string.h>

namespace NanoUI {

/**
 * @brief Toggle switch component
 * 
 * A binary on/off switch that can be tapped to change state.
 * Supports custom colors for active and inactive states.
 */
class UIToggle : public UIComponent {
public:
    bool toggled;
    uint16_t activeColor;
    uint16_t inactiveColor;
    char actionName[MAX_ID_LEN];

    UIToggle() 
        : toggled(false), activeColor(0x07E0), inactiveColor(0x7BEF) {
        actionName[0] = '\0';
    }

    const char* getType() const override { return "toggle"; }

    void setValue(int value) override {
        toggled = (value != 0);
        needsRedraw = true;
    }

    int getValue() const override {
        return toggled ? 1 : 0;
    }

    void setAction(const char* action) {
        if (action) {
            strncpy(actionName, action, MAX_ID_LEN - 1);
            actionName[MAX_ID_LEN - 1] = '\0';
        }
    }

    void draw(IDriver* driver) override;
    bool handleTouch(int16_t touchX, int16_t touchY, bool pressed) override;
};

} // namespace NanoUI

#endif // UI_TOGGLE_H

#include "UIToggle.h"

namespace NanoUI {

void UIToggle::draw(IDriver* driver) {
    if (!driver || !visible) return;

    uint16_t trackColor = toggled ? activeColor : inactiveColor;
    int16_t thumbRadius = height / 2 - 2;
    int16_t thumbX = toggled ? (x + width - thumbRadius - 2) : (x + thumbRadius + 2);
    int16_t thumbY = y + height / 2;

    // Draw track background
    driver->fillRect(x + thumbRadius, y + 2, width - 2 * thumbRadius, height - 4, trackColor);
    driver->fillCircle(x + thumbRadius, y + height / 2, height / 2 - 2, trackColor);
    driver->fillCircle(x + width - thumbRadius, y + height / 2, height / 2 - 2, trackColor);

    // Draw thumb
    driver->fillCircle(thumbX, thumbY, thumbRadius - 1, 0xFFFF);
}

bool UIToggle::handleTouch(int16_t touchX, int16_t touchY, bool pressed) {
    if (!enabled || !visible) return false;

    if (pressed && contains(touchX, touchY)) {
        toggled = !toggled;
        needsRedraw = true;
        return true;
    }
    return false;
}

} // namespace NanoUI

#ifndef UI_SLIDER_H
#define UI_SLIDER_H

#include "UIComponent.h"
#include "../drivers/IDriver.h"
#include <string.h>

namespace NanoUI {

/**
 * @brief Horizontal slider component
 * 
 * Allows selecting a value within a range by dragging a thumb.
 * Supports custom track and thumb colors.
 */
class UISlider : public UIComponent {
public:
    int minValue;
    int maxValue;
    int currentValue;
    uint16_t trackColor;
    uint16_t thumbColor;
    char actionName[MAX_ID_LEN];
    bool isDragging;

    UISlider() 
        : minValue(0), maxValue(100), currentValue(50),
          trackColor(0x7BEF), thumbColor(0xFFE0), isDragging(false) {
        actionName[0] = '\0';
    }

    const char* getType() const override { return "slider"; }

    void setValue(int value) override {
        if (value < minValue) value = minValue;
        if (value > maxValue) value = maxValue;
        currentValue = value;
        needsRedraw = true;
    }

    int getValue() const override {
        return currentValue;
    }

    void setAction(const char* action) {
        if (action) {
            strncpy(actionName, action, MAX_ID_LEN - 1);
            actionName[MAX_ID_LEN - 1] = '\0';
        }
    }

    void draw(IDriver* driver) override;
    bool handleTouch(int16_t touchX, int16_t touchY, bool pressed) override;

private:
    int16_t valueToX() const;
    int xToValue(int16_t touchX) const;
};

} // namespace NanoUI

#endif // UI_SLIDER_H

#include "UISlider.h"
#include <Arduino.h>

namespace NanoUI {

int16_t UISlider::valueToX() const {
    if (maxValue == minValue) return x + 8;
    long range = (long)maxValue - minValue;
    long pos = ((long)(currentValue - minValue) * (width - 16)) / range;
    return x + 8 + (int16_t)pos;
}

int UISlider::xToValue(int16_t touchX) const {
    if (width <= 16) return minValue;
    long relX = (long)(touchX - x - 8);
    if (relX < 0) relX = 0;
    if (relX > width - 16) relX = width - 16;
    long range = (long)maxValue - minValue;
    return minValue + (int)((relX * range) / (width - 16));
}

void UISlider::draw(IDriver* driver) {
    if (!driver || !visible) return;

    int16_t trackY = y + height / 2 - 2;
    int16_t thumbX = valueToX();
    int16_t thumbY = y + height / 2;
    int16_t thumbRadius = height / 2 - 2;

    // Draw track
    driver->fillRect(x + 8, trackY, width - 16, 4, trackColor);

    // Draw thumb
    driver->fillCircle(thumbX, thumbY, thumbRadius, thumbColor);
}

bool UISlider::handleTouch(int16_t touchX, int16_t touchY, bool pressed) {
    if (!enabled || !visible) return false;

    if (pressed) {
        if (contains(touchX, touchY) || isDragging) {
            int newValue = xToValue(touchX);
            if (newValue != currentValue) {
                currentValue = newValue;
                needsRedraw = true;
            }
            isDragging = true;
            return true;
        }
    } else {
        if (isDragging) {
            isDragging = false;
            return true;
        }
    }

    return false;
}

} // namespace NanoUI

#ifndef UI_IMAGE_H
#define UI_IMAGE_H

#include "UIComponent.h"
#include "../drivers/IDriver.h"
#include <string.h>

namespace NanoUI {

/**
 * @brief Maximum number of registered image symbols
 */
#ifndef MAX_IMAGE_SYMBOLS
#define MAX_IMAGE_SYMBOLS 10
#endif

/**
 * @brief Image symbol registry entry
 */
struct ImageSymbol {
    char name[MAX_ID_LEN];
    const uint16_t* data;
    int16_t width;
    int16_t height;
};

/**
 * @brief Image component that displays bitmaps from PROGMEM
 * 
 * Images must be pre-registered as symbols before parsing.
 * Use registerSymbol() to map a name to PROGMEM RGB565 data.
 */
class UIImage : public UIComponent {
public:
    char src[MAX_ID_LEN];
    const uint16_t* imageData;

    UIImage() : imageData(nullptr) {
        src[0] = '\0';
    }

    const char* getType() const override { return "image"; }

    void setSource(const char* source) {
        if (source) {
            strncpy(src, source, MAX_ID_LEN - 1);
            src[MAX_ID_LEN - 1] = '\0';
            resolveSymbol();
            needsRedraw = true;
        }
    }

    void draw(IDriver* driver) override;
    bool handleTouch(int16_t touchX, int16_t touchY, bool pressed) override;

    /**
     * @brief Register an image symbol globally
     * @param name Symbol name used in JSON
     * @param data Pointer to PROGMEM RGB565 data
     * @param w Image width
     * @param h Image height
     * @return True if registered successfully
     */
    static bool registerSymbol(const char* name, const uint16_t* data, int16_t w, int16_t h);

    /**
     * @brief Find registered symbol data by name
     * @param name Symbol name
     * @return Pointer to image data, or nullptr if not found
     */
    static const uint16_t* findSymbol(const char* name);

private:
    void resolveSymbol();
    static ImageSymbol _registry[MAX_IMAGE_SYMBOLS];
    static uint8_t _symbolCount;
};

} // namespace NanoUI

#endif // UI_IMAGE_H

#include "UIImage.h"
#include <string.h>

namespace NanoUI {

ImageSymbol UIImage::_registry[MAX_IMAGE_SYMBOLS];
uint8_t UIImage::_symbolCount = 0;

bool UIImage::registerSymbol(const char* name, const uint16_t* data, int16_t w, int16_t h) {
    if (_symbolCount >= MAX_IMAGE_SYMBOLS || !name || !data) return false;
    strncpy(_registry[_symbolCount].name, name, MAX_ID_LEN - 1);
    _registry[_symbolCount].name[MAX_ID_LEN - 1] = '\0';
    _registry[_symbolCount].data = data;
    _registry[_symbolCount].width = w;
    _registry[_symbolCount].height = h;
    _symbolCount++;
    return true;
}

const uint16_t* UIImage::findSymbol(const char* name) {
    for (uint8_t i = 0; i < _symbolCount; i++) {
        if (strcmp(_registry[i].name, name) == 0) {
            return _registry[i].data;
        }
    }
    return nullptr;
}

void UIImage::resolveSymbol() {
    imageData = findSymbol(src);
}

void UIImage::draw(IDriver* driver) {
    if (!driver || !visible) return;

    if (imageData) {
        driver->drawRGBBitmap(x, y, width, height, imageData);
    } else {
        // Draw placeholder rectangle if image not found
        driver->drawRect(x, y, width, height, 0xF800);
        driver->setCursor(x + 2, y + 2);
        driver->setTextColor(0xF800);
        driver->setTextSize(1);
        driver->print("?");
    }
}

bool UIImage::handleTouch(int16_t touchX, int16_t touchY, bool pressed) {
    (void)touchX;
    (void)touchY;
    (void)pressed;
    return false;
}

} // namespace NanoUI

